4', 'ffbca752-74db-4ae3-8e79-cd9ef61ceea5', 'ffc73946-f99c-4644-b808-05e77ce28f4d', 'ffc9a470-49cd-4774-a887-3e6ae7e760d5', 'ffca34e3-761b-4b69-adba-308097ac0f96', 'ffcd95f2-62a1-4ac9-befc-5a27909caadb', 'ffcf6a39-a9ef-4014-8a9e-34e34256397f', 'ffd281b2-49f0-45ad-b3f9-1888b200ca0b', 'ffd882f0-67f5-492c-9e44-b3509d945990', 'ffda34d9-46d6-40b4-9f14-0e977f5dfe79', 'ffdaec27-0ea4-4e03-8918-4433ca3643f5', 'ffdb560c-5a29-4fd3-98b2-ac897ab6f7d5', 'ffdc893a-aa18-4b66-995e-50b43a58c092', 'ffefe98d-3d29-4827-926a-e22120612c47', 'fffcf59f-a5bb-45fb-8472-9cf367a14494', 'ffff1c01-d522-483b-ac02-291bb2eed765'
  ]) AS user_id
),

c2_activity AS (
  SELECT
    w.user_id,
    u.last_match_finished_at,
    DATE_DIFF(CURRENT_DATE(), DATE(u.last_match_finished_at), DAY) AS days_since_last_match,
    (SELECT MAX(l.timestamp) FROM UNNEST(u.logins) AS l) AS last_login,
    DATE_DIFF(CURRENT_DATE(), DATE((SELECT MAX(l.timestamp) FROM UNNEST(u.logins) AS l)), DAY) AS days_since_last_login
  FROM c2_ids w
  LEFT JOIN `business-intelligence-prod.DataMart.Users` u
    ON w.user_id = u.user_id
)

SELECT
  COUNT(*) AS total_c2,
  COUNTIF(last_match_finished_at IS NOT NULL) AS matched_in_datamart,

  -- Activity by last match played
  COUNTIF(days_since_last_match <= 7) AS match_active_7d,
  COUNTIF(days_since_last_match <= 14) AS match_active_14d,
  COUNTIF(days_since_last_match <= 30) AS match_active_30d,
  COUNTIF(days_since_last_match <= 90) AS match_active_90d,
  COUNTIF(days_since_last_match > 90) AS match_dormant_90d_plus,
  COUNTIF(last_match_finished_at IS NULL) AS never_matched,

  -- Activity by last login
  COUNTIF(days_since_last_login <= 7) AS login_active_7d,
  COUNTIF(days_since_last_login <= 30) AS login_active_30d,
  COUNTIF(days_since_last_login <= 90) AS login_active_90d

FROM c2_activity
